c
// Checks if current thread has 'cap' in a targeted namespace
bool ns_capable(struct user_namespace *ns, int cap) {
if (security_capable(current_cred(), ns, cap) == 0)
return true;
return false;
}

// Checks if current thread has 'cap' in the ROOT namespace
bool capable(int cap) {
// Points strictly to &init_user_ns
return ns_capable(&init_user_ns, cap);
}
